     1→import { create } from 'zustand';
     2→import { persist } from 'zustand/middleware';
     3→import type { TimeEntry, TimeTrackingProject, EntryFilters, TimeViewMode, TimeTrackingState, DailySummary, WeeklySummary, MonthlyReport, ProjectSummary } from '../types';
     4→import { timeTrackingDb } from '../db/timeTrackingDb';
     5→import { logger } from '../services/logger';
     6→
     7→const log = logger.module('TimeTracking');
     8→
     9→interface TimeTrackingStore extends TimeTrackingState {
    10→  // ==================== TIMER ACTIONS ====================
    11→
    12→  /**
    13→   * Start a new timer
    14→   */
    15→  startTimer: (params: { description: string; projectId?: string; taskId?: string; billable?: boolean }) => void;
    16→
    17→  /**
    18→   * Stop the currently running timer
    19→   */
    20→  stopTimer: () => Promise<void>;
    21→
    22→  /**
    23→   * Pause the currently running timer
    24→   */
    25→  pauseTimer: () => void;
    26→
    27→  /**
    28→   * Resume a paused timer
    29→   */
    30→  resumeTimer: () => void;
    31→
    32→  /**
    33→   * Update the active timer (e.g., change description or project)
    34→   */
    35→  updateActiveEntry: (updates: Partial<TimeEntry>) => void;
    36→
    37→  /**
    38→   * Update just the timer description (convenience method)
    39→   */
    40→  updateTimerDescription: (description: string) => void;
    41→
    42→  // ==================== COMPUTED GETTERS ====================
    43→
    44→  /**
    45→   * Check if timer is currently running
    46→   */
    47→  isTimerRunning: () => boolean;
    48→
    49→  /**
    50→   * Get current timer description
    51→   */
    52→  timerDescription: () => string | null;
    53→
    54→  /**
    55→   * Get current timer project ID
    56→   */
    57→  timerProjectId: () => string | null;
    58→
    59→  // ==================== ENTRY ACTIONS ====================
    60→
    61→  /**
    62→   * Add a manual time entry (retroactive logging)
    63→   */
    64→  addManualEntry: (entry: Omit<TimeEntry, 'id' | 'createdAt' | 'updatedAt' | 'workspaceId'>) => Promise<void>;
    65→
    66→  /**
    67→   * Update an existing time entry
    68→   */
    69→  updateEntry: (id: string, updates: Partial<TimeEntry>) => Promise<void>;
    70→
    71→  /**
    72→   * Delete a time entry
    73→   */
    74→  deleteEntry: (id: string) => Promise<void>;
    75→
    76→  /**
    77→   * Duplicate a time entry (for quick re-entry)
    78→   */
    79→  duplicateEntry: (id: string) => Promise<void>;
    80→
    81→  /**
    82→   * Continue from a previous entry (start new timer with same details)
    83→   */
    84→  continueEntry: (id: string) => void;
    85→
    86→  // ==================== PROJECT ACTIONS ====================
    87→
    88→  /**
    89→   * Add a new project
    90→   */
    91→  addProject: (project: Omit<TimeTrackingProject, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
    92→
    93→  /**
    94→   * Update an existing project
    95→   */
    96→  updateProject: (id: string, updates: Partial<TimeTrackingProject>) => Promise<void>;
    97→
    98→  /**
    99→   * Delete a project (and all its entries)
   100→   */
   101→  deleteProject: (id: string) => Promise<void>;
   102→
   103→  /**
   104→   * Archive a project
   105→   */
   106→  archiveProject: (id: string) => Promise<void>;
   107→
   108→  /**
   109→   * Unarchive a project
   110→   */
   111→  unarchiveProject: (id: string) => Promise<void>;
   112→
   113→  // ==================== QUERY ACTIONS ====================
   114→
   115→  /**
   116→   * Load entries from database with optional filters
   117→   */
   118→  loadEntries: (filters?: EntryFilters) => Promise<void>;
   119→
   120→  /**
   121→   * Load projects from database
   122→   */
   123→  loadProjects: () => Promise<void>;
   124→
   125→  /**
   126→   * Get entries by date range
   127→   */
   128→  getEntriesByDateRange: (start: Date, end: Date) => TimeEntry[];
   129→
   130→  /**
   131→   * Get entries by project
   132→   */
   133→  getEntriesByProject: (projectId: string) => TimeEntry[];
   134→
   135→  // ==================== FILTER ACTIONS ====================
   136→
   137→  /**
   138→   * Set filters for entry list
   139→   */
   140→  setFilters: (filters: Partial<EntryFilters>) => void;
   141→
   142→  /**
   143→   * Clear all filters
   144→   */
   145→  clearFilters: () => void;
   146→
   147→  /**
   148→   * Set view mode
   149→   */
   150→  setViewMode: (mode: TimeViewMode) => void;
   151→
   152→  // ==================== UTILITY ACTIONS ====================
   153→
   154→  /**
   155→   * Get total time tracked for current filters
   156→   */
   157→  getTotalTime: () => number;
   158→
   159→  /**
   160→   * Get time tracked by project (for reports)
   161→   */
   162→  getTimeByProject: () => Record<string, number>;
   163→
   164→  /**
   165→   * Get recent time entries (for sidebar panel)
   166→   */
   167→  getRecentEntries: (hours: number) => Promise<TimeEntry[]>;
   168→
   169→  /**
   170→   * Get today's total time tracked (in seconds)
   171→   */
   172→  getTodayTotal: () => Promise<number>;
   173→
   174→  /**
   175→   * Get daily summary for the last N days
   176→   */
   177→  getDailySummary: (days: number) => Promise<DailySummary[]>;
   178→
   179→  /**
   180→   * Get weekly summary for current week (Mon-Sun)
   181→   */
   182→  getWeeklySummary: () => Promise<WeeklySummary>;
   183→
   184→  /**
   185→   * Get monthly report for a specific month
   186→   */
   187→  getMonthlyReport: (year: number, month: number) => Promise<MonthlyReport>;
   188→
   189→  /**
   190→   * Get project summary (time by project) for current filters
   191→   */
   192→  getProjectSummary: () => Promise<ProjectSummary[]>;
   193→
   194→  /**
   195→   * Export entries to CSV format
   196→   */
   197→  exportToCSV: (entries: TimeEntry[]) => string;
   198→
   199→  /**
   200→   * Bulk delete multiple entries
   201→   */
   202→  bulkDeleteEntries: (ids: string[]) => Promise<void>;
   203→
   204→  /**
   205→   * Bulk update multiple entries (e.g., assign project)
   206→   */
   207→  bulkUpdateEntries: (ids: string[], updates: Partial<TimeEntry>) => Promise<void>;
   208→
   209→  // ==================== PHASE A: KANBAN INTEGRATION ====================
   210→
   211→  /**
   212→   * Get all time entries for a specific Kanban card
   213→   */
   214→  getEntriesForCard: (cardId: string) => TimeEntry[];
   215→
   216→  /**
   217→   * Get total time logged for a specific Kanban card (in seconds)
   218→   */
   219→  getTotalTimeForCard: (cardId: string) => number;
   220→
   221→  /**
   222→   * Start timer for a specific Kanban card
   223→   */
   224→  startTimerForCard: (cardId: string, taskName: string) => void;
   225→}
   226→
   227→const DEFAULT_WORKSPACE_ID = 'default';
   228→
   229→export const useTimeTrackingStore = create<TimeTrackingStore>()(
   230→  persist(
   231→    (set, get) => ({
   232→      // ==================== INITIAL STATE ====================
   233→      activeEntry: null,
   234→      entries: [],
   235→      projects: [],
   236→      selectedDate: new Date().toISOString().split('T')[0],
   237→      selectedProject: null,
   238→      selectedTags: [],
   239→      viewMode: 'list',
   240→      filters: {
   241→        dateRange: 'last7days',
   242→        projectIds: [],
   243→        tags: [],
   244→        searchQuery: ''
   245→      },
   246→      reminderEnabled: false,
   247→      idleDetectionMinutes: 0,
   248→      roundingMinutes: 0,
   249→
   250→      // ==================== TIMER ACTIONS ====================
   251→
   252→      startTimer: ({ description, projectId, taskId, billable = true }) => {
   253→        const entry: TimeEntry = {
   254→          id: crypto.randomUUID(),
   255→          workspaceId: DEFAULT_WORKSPACE_ID,
   256→          description,
   257→          projectId,
   258→          taskId,
   259→          startTime: new Date().toISOString(),
   260→          duration: 0,
   261→          billable,
   262→          tags: [],
   263→          createdAt: new Date().toISOString(),
   264→          updatedAt: new Date().toISOString()
   265→        };
   266→
   267→        set({ activeEntry: entry });
   268→
   269→        // Save to localStorage for persistence (backup)
   270→        localStorage.setItem('activeTimer', JSON.stringify(entry));
   271→      },
   272→
   273→      pauseTimer: () => {
   274→        const { activeEntry } = get();
   275→        if (!activeEntry) return;
   276→
   277→        const now = new Date().toISOString();
   278→        const pausedEntry = {
   279→          ...activeEntry,
   280→          pausedAt: now,
   281→          isPaused: true,
   282→          updatedAt: now
   283→        };
   284→
   285→        set({ activeEntry: pausedEntry });
   286→        localStorage.setItem('activeTimer', JSON.stringify(pausedEntry));
   287→      },
   288→
   289→      resumeTimer: () => {
   290→        const { activeEntry } = get();
   291→        if (!activeEntry || !activeEntry.isPaused) return;
   292→
   293→        const now = new Date().toISOString();
   294→        const pausedDuration = activeEntry.pausedAt
   295→          ? new Date(now).getTime() - new Date(activeEntry.pausedAt).getTime()
   296→          : 0;
   297→
   298→        const resumedEntry = {
   299→          ...activeEntry,
   300→          startTime: new Date(
   301→            new Date(activeEntry.startTime).getTime() + pausedDuration
   302→          ).toISOString(),
   303→          isPaused: false,
   304→          pausedAt: undefined,
   305→          updatedAt: now
   306→        };
   307→
   308→        set({ activeEntry: resumedEntry });
   309→        localStorage.setItem('activeTimer', JSON.stringify(resumedEntry));
   310→      },
   311→
   312→      stopTimer: async () => {
   313→        const { activeEntry, entries } = get();
   314→        if (!activeEntry) return;
   315→
   316→        const endTime = new Date().toISOString();
   317→        const duration = Math.floor(
   318→          (new Date(endTime).getTime() - new Date(activeEntry.startTime).getTime()) / 1000
   319→        );
   320→
   321→        const completedEntry: TimeEntry = {
   322→          ...activeEntry,
   323→          endTime,
   324→          duration,
   325→          updatedAt: new Date().toISOString()
   326→        };
   327→
   328→        // Save to IndexedDB
   329→        await timeTrackingDb.addEntry(completedEntry);
   330→
   331→        // Update state
   332→        set({
   333→          activeEntry: null,
   334→          entries: [completedEntry, ...entries]
   335→        });
   336→
   337→        // Clear localStorage backup
   338→        localStorage.removeItem('activeTimer');
   339→      },
   340→
   341→      updateActiveEntry: (updates) => {
   342→        const { activeEntry } = get();
   343→        if (!activeEntry) return;
   344→
   345→        const updatedEntry = {
   346→          ...activeEntry,
   347→          ...updates,
   348→          updatedAt: new Date().toISOString()
   349→        };
   350→
   351→        set({ activeEntry: updatedEntry });
   352→
   353→        // Update localStorage backup
   354→        localStorage.setItem('activeTimer', JSON.stringify(updatedEntry));
   355→      },
   356→
   357→      updateTimerDescription: (description) => {
   358→        get().updateActiveEntry({ description });
   359→      },
   360→
   361→      // ==================== COMPUTED GETTERS ====================
   362→
   363→      isTimerRunning: () => {
   364→        const { activeEntry } = get();
   365→        return activeEntry !== null && !activeEntry.isPaused;
   366→      },
   367→
   368→      timerDescription: () => {
   369→        const { activeEntry } = get();
   370→        return activeEntry?.description || null;
   371→      },
   372→
   373→      timerProjectId: () => {
   374→        const { activeEntry } = get();
   375→        return activeEntry?.projectId || null;
   376→      },
   377→
   378→      // ==================== ENTRY ACTIONS ====================
   379→
   380→      addManualEntry: async (entryData) => {
   381→        const { entries } = get();
   382→
   383→        const entry: TimeEntry = {
   384→          ...entryData,
   385→          id: crypto.randomUUID(),
   386→          workspaceId: DEFAULT_WORKSPACE_ID,
   387→          createdAt: new Date().toISOString(),
   388→          updatedAt: new Date().toISOString()
   389→        };
   390→
   391→        // Save to IndexedDB
   392→        await timeTrackingDb.addEntry(entry);
   393→
   394→        // Update state
   395→        set({ entries: [entry, ...entries] });
   396→      },
   397→
   398→      updateEntry: async (id, updates) => {
   399→        const { entries } = get();
   400→
   401→        // Update in IndexedDB
   402→        await timeTrackingDb.updateEntry(id, updates);
   403→
   404→        // Update state
   405→        const updatedEntries = entries.map(entry =>
   406→          entry.id === id
   407→            ? { ...entry, ...updates, updatedAt: new Date().toISOString() }
   408→            : entry
   409→        );
   410→
   411→        set({ entries: updatedEntries });
   412→      },
   413→
   414→      deleteEntry: async (id) => {
   415→        const { entries } = get();
   416→
   417→        // Delete from IndexedDB
   418→        await timeTrackingDb.deleteEntry(id);
   419→
   420→        // Update state
   421→        set({ entries: entries.filter(entry => entry.id !== id) });
   422→      },
   423→
   424→      duplicateEntry: async (id) => {
   425→        const { entries } = get();
   426→        const entry = entries.find(e => e.id === id);
   427→        if (!entry) return;
   428→
   429→        const newEntry: TimeEntry = {
   430→          ...entry,
   431→          id: crypto.randomUUID(),
   432→          startTime: new Date().toISOString(),
   433→          endTime: undefined,
   434→          duration: 0,
   435→          createdAt: new Date().toISOString(),
   436→          updatedAt: new Date().toISOString()
   437→        };
   438→
   439→        // Save to IndexedDB
   440→        await timeTrackingDb.addEntry(newEntry);
   441→
   442→        // Update state
   443→        set({ entries: [newEntry, ...entries] });
   444→      },
   445→
   446→      continueEntry: (id) => {
   447→        const { entries, startTimer } = get();
   448→        const entry = entries.find(e => e.id === id);
   449→        if (!entry) return;
   450→
   451→        // Start a new timer with the same details
   452→        startTimer({
   453→          description: entry.description,
   454→          projectId: entry.projectId,
   455→          taskId: entry.taskId
   456→        });
   457→
   458→        // Copy tags if any
   459→        const { activeEntry } = get();
   460→        if (activeEntry) {
   461→          get().updateActiveEntry({ tags: entry.tags });
   462→        }
   463→      },
   464→
   465→      // ==================== PROJECT ACTIONS ====================
   466→
   467→      addProject: async (projectData) => {
   468→        const { projects } = get();
   469→
   470→        const project: TimeTrackingProject = {
   471→          ...projectData,
   472→          id: crypto.randomUUID(),
   473→          createdAt: new Date().toISOString(),
   474→          updatedAt: new Date().toISOString()
   475→        };
   476→
   477→        // Save to IndexedDB
   478→        await timeTrackingDb.addProject(project);
   479→
   480→        // Update state
   481→        set({ projects: [...projects, project] });
   482→      },
   483→
   484→      updateProject: async (id, updates) => {
   485→        const { projects } = get();
   486→
   487→        // Update in IndexedDB
   488→        await timeTrackingDb.updateProject(id, updates);
   489→
   490→        // Update state
   491→        const updatedProjects = projects.map(project =>
   492→          project.id === id
   493→            ? { ...project, ...updates, updatedAt: new Date().toISOString() }
   494→            : project
   495→        );
   496→
   497→        set({ projects: updatedProjects });
   498→      },
   499→
   500→      deleteProject: async (id) => {
   501→        const { projects } = get();
   502→
   503→        // Delete from IndexedDB (will also delete all entries)
   504→        await timeTrackingDb.deleteProject(id);
   505→
   506→        // Update state
   507→        set({ projects: projects.filter(project => project.id !== id) });
   508→
   509→        // Reload entries to remove deleted project's entries
   510→        await get().loadEntries();
   511→      },
   512→
   513→      archiveProject: async (id) => {
   514→        await timeTrackingDb.archiveProject(id);
   515→        await get().loadProjects();
   516→      },
   517→
   518→      unarchiveProject: async (id) => {
   519→        await timeTrackingDb.unarchiveProject(id);
   520→        await get().loadProjects();
   521→      },
   522→
   523→      // ==================== QUERY ACTIONS ====================
   524→
   525→      loadEntries: async (filters) => {
   526→        let startDate: Date | undefined;
   527→        let endDate: Date | undefined;
   528→
   529→        // Calculate date range based on filter
   530→        if (filters?.dateRange) {
   531→          const now = new Date();
   532→          switch (filters.dateRange) {
   533→            case 'today':
   534→              startDate = new Date(now.setHours(0, 0, 0, 0));
   535→              endDate = new Date(now.setHours(23, 59, 59, 999));
   536→              break;
   537→            case 'yesterday':
   538→              startDate = new Date(now.setDate(now.getDate() - 1));
   539→              startDate.setHours(0, 0, 0, 0);
   540→              endDate = new Date(startDate);
   541→              endDate.setHours(23, 59, 59, 999);
   542→              break;
   543→            case 'last7days':
   544→              startDate = new Date(now.setDate(now.getDate() - 7));
   545→              startDate.setHours(0, 0, 0, 0);
   546→              endDate = new Date();
   547→              break;
   548→            case 'last30days':
   549→              startDate = new Date(now.setDate(now.getDate() - 30));
   550→              startDate.setHours(0, 0, 0, 0);
   551→              endDate = new Date();
   552→              break;
   553→            case 'custom':
   554→              if (filters.startDate) startDate = new Date(filters.startDate);
   555→              if (filters.endDate) endDate = new Date(filters.endDate);
   556→              break;
   557→          }
   558→        }
   559→
   560→        const entries = await timeTrackingDb.getEntries({
   561→          startDate,
   562→          endDate,
   563→          projectId: filters?.projectIds?.[0], // For now, single project filter
   564→          searchQuery: filters?.searchQuery
   565→        });
   566→
   567→        set({ entries });
   568→      },
   569→
   570→      loadProjects: async () => {
   571→        const projects = await timeTrackingDb.getProjects();
   572→        set({ projects });
   573→      },
   574→
   575→      getEntriesByDateRange: (start, end) => {
   576→        const { entries } = get();
   577→        return entries.filter(entry => {
   578→          const entryDate = new Date(entry.startTime);
   579→          return entryDate >= start && entryDate <= end;
   580→        });
   581→      },
   582→
   583→      getEntriesByProject: (projectId) => {
   584→        const { entries } = get();
   585→        return entries.filter(entry => entry.projectId === projectId);
   586→      },
   587→
   588→      // ==================== FILTER ACTIONS ====================
   589→
   590→      setFilters: (newFilters) => {
   591→        const { filters } = get();
   592→        const updatedFilters = { ...filters, ...newFilters };
   593→        set({ filters: updatedFilters });
   594→
   595→        // Reload entries with new filters
   596→        get().loadEntries(updatedFilters);
   597→      },
   598→
   599→      clearFilters: () => {
   600→        const defaultFilters: EntryFilters = {
   601→          dateRange: 'last7days',
   602→          projectIds: [],
   603→          tags: [],
   604→          searchQuery: ''
   605→        };
   606→        set({ filters: defaultFilters });
   607→        get().loadEntries(defaultFilters);
   608→      },
   609→
   610→      setViewMode: (mode) => {
   611→        set({ viewMode: mode });
   612→      },
   613→
   614→      // ==================== UTILITY ACTIONS ====================
   615→
   616→      getTotalTime: () => {
   617→        const { entries } = get();
   618→        return entries.reduce((total, entry) => total + entry.duration, 0);
   619→      },
   620→
   621→      getTimeByProject: () => {
   622→        const { entries } = get();
   623→        const timeByProject: Record<string, number> = {};
   624→
   625→        entries.forEach(entry => {
   626→          const projectId = entry.projectId || 'no-project';
   627→          timeByProject[projectId] = (timeByProject[projectId] || 0) + entry.duration;
   628→        });
   629→
   630→        return timeByProject;
   631→      },
   632→
   633→      getRecentEntries: async (hours) => {
   634→        const now = new Date();
   635→        const startDate = new Date(now.getTime() - hours * 60 * 60 * 1000);
   636→
   637→        const entries = await timeTrackingDb.getEntriesByDateRange(startDate, now);
   638→        return entries;
   639→      },
   640→
   641→      getTodayTotal: async () => {
   642→        const now = new Date();
   643→        const startOfDay = new Date(now);
   644→        startOfDay.setHours(0, 0, 0, 0);
   645→        const endOfDay = new Date(now);
   646→        endOfDay.setHours(23, 59, 59, 999);
   647→
   648→        const entries = await timeTrackingDb.getEntriesByDateRange(startOfDay, endOfDay);
   649→        const total = entries.reduce((sum, entry) => sum + entry.duration, 0);
   650→
   651→        // Add active timer duration if running
   652→        const { activeEntry } = get();
   653→        if (activeEntry && !activeEntry.isPaused) {
   654→          const start = new Date(activeEntry.startTime).getTime();
   655→          const currentDuration = Math.floor((Date.now() - start) / 1000);
   656→          return total + currentDuration;
   657→        }
   658→
   659→        return total;
   660→      },
   661→
   662→      getDailySummary: async (days) => {
   663→        const now = new Date();
   664→        const startDate = new Date(now);
   665→        startDate.setDate(startDate.getDate() - days + 1);
   666→        startDate.setHours(0, 0, 0, 0);
   667→
   668→        const endDate = new Date(now);
   669→        endDate.setHours(23, 59, 59, 999);
   670→
   671→        const entries = await timeTrackingDb.getEntriesByDateRange(startDate, endDate);
   672→
   673→        // Group entries by date
   674→        const entriesByDate = new Map<string, TimeEntry[]>();
   675→        entries.forEach(entry => {
   676→          const date = new Date(entry.startTime).toISOString().split('T')[0];
   677→          if (!entriesByDate.has(date)) {
   678→            entriesByDate.set(date, []);
   679→          }
   680→          entriesByDate.get(date)!.push(entry);
   681→        });
   682→
   683→        // Create daily summaries for last N days
   684→        const summaries: DailySummary[] = [];
   685→        for (let i = days - 1; i >= 0; i--) {
   686→          const date = new Date(now);
   687→          date.setDate(date.getDate() - i);
   688→          const dateStr = date.toISOString().split('T')[0];
   689→
   690→          const dayEntries = entriesByDate.get(dateStr) || [];
   691→          const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
   692→
   693→          summaries.push({
   694→            date: dateStr,
   695→            totalDuration,
   696→            entryCount: dayEntries.length
   697→          });
   698→        }
   699→
   700→        return summaries;
   701→      },
   702→
   703→      getWeeklySummary: async () => {
   704→        const now = new Date();
   705→
   706→        // Get Monday of current week
   707→        const dayOfWeek = now.getDay();
   708→        const daysFromMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
   709→        const weekStart = new Date(now);
   710→        weekStart.setDate(weekStart.getDate() - daysFromMonday);
   711→        weekStart.setHours(0, 0, 0, 0);
   712→
   713→        // Get Sunday of current week
   714→        const weekEnd = new Date(weekStart);
   715→        weekEnd.setDate(weekEnd.getDate() + 6);
   716→        weekEnd.setHours(23, 59, 59, 999);
   717→
   718→        const entries = await timeTrackingDb.getEntriesByDateRange(weekStart, weekEnd);
   719→
   720→        // Group entries by date
   721→        const entriesByDate = new Map<string, TimeEntry[]>();
   722→        entries.forEach(entry => {
   723→          const date = new Date(entry.startTime).toISOString().split('T')[0];
   724→          if (!entriesByDate.has(date)) {
   725→            entriesByDate.set(date, []);
   726→          }
   727→          entriesByDate.get(date)!.push(entry);
   728→        });
   729→
   730→        // Create daily breakdown for all 7 days
   731→        const dailyBreakdown: DailySummary[] = [];
   732→        for (let i = 0; i < 7; i++) {
   733→          const date = new Date(weekStart);
   734→          date.setDate(date.getDate() + i);
   735→          const dateStr = date.toISOString().split('T')[0];
   736→
   737→          const dayEntries = entriesByDate.get(dateStr) || [];
   738→          const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
   739→
   740→          dailyBreakdown.push({
   741→            date: dateStr,
   742→            totalDuration,
   743→            entryCount: dayEntries.length
   744→          });
   745→        }
   746→
   747→        // Calculate weekly totals
   748→        const totalDuration = entries.reduce((sum, entry) => sum + entry.duration, 0);
   749→
   750→        return {
   751→          weekStart: weekStart.toISOString().split('T')[0],
   752→          weekEnd: weekEnd.toISOString().split('T')[0],
   753→          totalDuration,
   754→          entryCount: entries.length,
   755→          dailyBreakdown
   756→        };
   757→      },
   758→
   759→      getMonthlyReport: async (year, month) => {
   760→        const { projects } = get();
   761→
   762→        // Get all days in month (28-31 days)
   763→        const daysInMonth = new Date(year, month + 1, 0).getDate();
   764→
   765→        // Start of month
   766→        const monthStart = new Date(year, month, 1, 0, 0, 0, 0);
   767→
   768→        // End of month
   769→        const monthEnd = new Date(year, month, daysInMonth, 23, 59, 59, 999);
   770→
   771→        const entries = await timeTrackingDb.getEntriesByDateRange(monthStart, monthEnd);
   772→
   773→        // Group entries by date
   774→        const entriesByDate = new Map<string, TimeEntry[]>();
   775→        entries.forEach(entry => {
   776→          const date = new Date(entry.startTime).toISOString().split('T')[0];
   777→          if (!entriesByDate.has(date)) {
   778→            entriesByDate.set(date, []);
   779→          }
   780→          entriesByDate.get(date)!.push(entry);
   781→        });
   782→
   783→        // Create daily breakdown for all days in month
   784→        const dailyBreakdown: DailySummary[] = [];
   785→        for (let day = 1; day <= daysInMonth; day++) {
   786→          const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
   787→          const dayEntries = entriesByDate.get(dateStr) || [];
   788→          const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
   789→
   790→          dailyBreakdown.push({
   791→            date: dateStr,
   792→            totalDuration,
   793→            entryCount: dayEntries.length
   794→          });
   795→        }
   796→
   797→        // Calculate project breakdown
