   806→            projectMap.set(projectId, {
   807→              projectId,
   808→              projectName: project?.name || 'No Project',
   809→              projectColor: project?.color || '#94A3B8', // Default gray
   810→              totalDuration: 0,
   811→              entryCount: 0,
   812→              percentage: 0
   813→            });
   814→          }
   815→
   816→          const summary = projectMap.get(projectId)!;
