   860→
   861→          const summary = projectMap.get(projectId)!;
   862→          summary.totalDuration += entry.duration;
   863→          summary.entryCount += 1;
   864→        });
   865→
   866→        // Calculate percentages and convert to array
   867→        const projectSummaries = Array.from(projectMap.values()).map(summary => ({
   868→          ...summary,
   869→          percentage: totalTime > 0 ? (summary.totalDuration / totalTime) * 100 : 0
   870→        }));
   871→
   872→        // Sort by duration descending
   873→        return projectSummaries.sort((a, b) => b.totalDuration - a.totalDuration);
   874→      },
   875→
   876→      exportToCSV: (entries) => {
   877→        const { projects } = get();
   878→
   879→        // CSV Header
   880→        const header = 'Date,Start Time,End Time,Duration,Description,Project,Notes\n';
   881→
   882→        // CSV Rows
   883→        const rows = entries.map(entry => {
   884→          const startDate = new Date(entry.startTime);
   885→          const endDate = entry.endTime ? new Date(entry.endTime) : null;
   886→
   887→          const date = startDate.toLocaleDateString('en-US', {
   888→            year: 'numeric',
   889→            month: '2-digit',
   890→            day: '2-digit'
   891→          });
   892→
   893→          const startTime = startDate.toLocaleTimeString('en-US', {
   894→            hour: '2-digit',
   895→            minute: '2-digit',
   896→            hour12: false
   897→          });
   898→
   899→          const endTime = endDate ? endDate.toLocaleTimeString('en-US', {
   900→            hour: '2-digit',
   901→            minute: '2-digit',
   902→            hour12: false
   903→          }) : '';
   904→
   905→          // Format duration as HH:MM
   906→          const hours = Math.floor(entry.duration / 3600);
   907→          const minutes = Math.floor((entry.duration % 3600) / 60);
   908→          const duration = `${hours}h ${minutes.toString().padStart(2, '0')}m`;
   909→
   910→          const project = entry.projectId
   911→            ? projects.find(p => p.id === entry.projectId)?.name || ''
   912→            : '';
   913→
   914→          // Escape commas and quotes in text fields
   915→          const escapeCSV = (str: string) => {
   916→            if (!str) return '';
   917→            if (str.includes(',') || str.includes('"') || str.includes('\n')) {
   918→              return `"${str.replace(/"/g, '""')}"`;
   919→            }
   920→            return str;
   921→          };
   922→
   923→          return `${date},${startTime},${endTime},${duration},${escapeCSV(entry.description)},${escapeCSV(project)},${escapeCSV(entry.notes || '')}`;
   924→        }).join('\n');
   925→
   926→        return header + rows;
   927→      },
   928→
   929→      bulkDeleteEntries: async (ids) => {
   930→        const { entries } = get();
   931→
   932→        // Delete from IndexedDB
   933→        await Promise.all(ids.map(id => timeTrackingDb.deleteEntry(id)));
   934→
   935→        // Update state
   936→        set({ entries: entries.filter(entry => !ids.includes(entry.id)) });
   937→      },
   938→
   939→      bulkUpdateEntries: async (ids, updates) => {
   940→        const { entries } = get();
   941→
   942→        // Update in IndexedDB
   943→        await Promise.all(ids.map(id => timeTrackingDb.updateEntry(id, updates)));
   944→
   945→        // Update state
   946→        const updatedEntries = entries.map(entry =>
   947→          ids.includes(entry.id)
   948→            ? { ...entry, ...updates, updatedAt: new Date().toISOString() }
   949→            : entry
   950→        );
   951→
   952→        set({ entries: updatedEntries });
   953→      },
   954→
   955→      // ==================== PHASE A: KANBAN INTEGRATION ====================
   956→
   957→      getEntriesForCard: (cardId) => {
