   981→      }
   982→    }),
   983→    {
   984→      name: 'time-tracking-storage',
   985→      partialize: (state) => ({
   986→        // Only persist active timer and settings (entries stored in IndexedDB)
   987→        activeEntry: state.activeEntry,
